    "user_id": {"type": "integer", "min": 1, "required": True},
    "quantity": {"type": "integer", "min": 1, "max": 1000, "required": True},
    "unit_price": {"type": "float", "min": 0.01, "required": True},
    "status": {
        "type": "string",
        "allowed": ["pending", "shipped", "delivered", "cancelled"]
    }
}

v = Validator(schema)

