from pydantic import ValidationError

def process_kafka_message(message: dict):
    try:
        record = OrderRecord(**message)
        # Forward to processing
        downstream_process(record)
    except ValidationError as e:
        # Route to dead-letter topic
        dead_letter_producer.send("orders-dead-letter", {
            "original": message,
            "errors": e.errors(),
            "timestamp": datetime.utcnow().isoformat()
        })
